// 1. Hacemos la petición a la API de la UNLP
const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://gestionapp.info.unlp.edu.ar/api/CALENDARIO_ACADEMICO',
    json: true
});

// 2. Función para limpiar HTML (quita tags y espacios extra)
function cleanHtml(text) {
    if (!text) return '';
    // Reemplaza cualquier tag HTML (<...>) por un salto de línea
    let clean = text.replace(/<[^>]+>/g, '\n');
    // Reemplaza múltiples espacios/saltos por uno solo
    clean = clean.replace(/\s+/g, ' ').trim();
    return clean;
}

// 3. Procesamos los datos para reducir tamaño
const cleanData = response.map(item => {
    return {
        calendario: item.nombre,
        contenido: cleanHtml(item.contenido)
    };
});

// 4. 🔥 CORRECCIÓN: Convertimos el objeto a TEXTO (String) para que el Agente lo entienda
return JSON.stringify(cleanData);

// 1. LA HERRAMIENTA HACE SU PROPIA PETICIÓN (Autónoma)
// Esto asegura que los datos siempre estén disponibles cuando el Agente llame a la Tool
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestiondocente.info.unlp.edu.ar/api/v2/materias.json',
  json: true
});

// 2. EXTRAER EL ARRAY DE MATERIAS DEL RESULTADO
const materias = response._embedded?.materias || [];

// 3. EXTRAER SOLO LOS NOMBRES, LIMPIAR Y ELIMINAR DUPLICADOS
const nombresUnicos = [...new Set(materias.map(m => m.nombre ? m.nombre.trim() : ""))].filter(n => n !== "");

// 4. ORDENAR ALFABÉTICAMENTE
nombresUnicos.sort((a, b) => a.localeCompare(b));

// 5. VALIDACIÓN
if (nombresUnicos.length === 0) {
    return "No se pudo obtener la lista de materias en este momento.";
}

// 6. RETORNAR EL STRING PLANO
// El Agente recibirá esto y Groq decidirá qué mostrar según la pregunta del usuario
return "LISTADO COMPLETO DE MATERIAS:\n" + nombresUnicos.join('\n');

// 1. PETICIÓN AUTÓNOMA AL ENDPOINT DEL TIMELINE
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestiondocente.info.unlp.edu.ar/api/v2/timeline.json',
  json: true
});

// 2. EXTRAER EL CONTENIDO RELEVANTE
const items = response._embedded?.content || [];

// 3. PROCESAR Y LIMPIAR LAS NOTICIAS
const noticiasProcesadas = items.map(item => {
    const data = item._embedded?.noticia;
    if (!data) return null;

    // Formatear la fecha a algo más legible
    const fechaLimpia = data.fecha ? data.fecha.split('T')[0] : "Fecha no disponible";

    // Limpieza profunda de HTML del cuerpo de la noticia
    const cuerpoLimpio = data.cuerpo
        .replace(/<[^>]*>?/gm, ' ') // Quita etiquetas HTML
        .replace(/&bull;/g, '•')     // Convierte viñetas
        .replace(/&nbsp;/g, ' ')    // Quita espacios HTML
        .replace(/&aacute;/g, 'á').replace(/&eacute;/g, 'é').replace(/&iacute;/g, 'í').replace(/&oacute;/g, 'ó').replace(/&uacute;/g, 'ú')
        .replace(/&ntilde;/g, 'ñ').replace(/&iquest;/g, '¿')
        .replace(/\s+/g, ' ')       // Quita espacios múltiples
        .trim();

    // Devolvemos un string compacto por cada noticia
    return `[${fechaLimpia}] TITULO: ${data.titulo}\nRESUMEN: ${cuerpoLimpio.substring(0, 300)}...`;
}).filter(n => n !== null);

// 4. VALIDACIÓN DE RESULTADOS
if (noticiasProcesadas.length === 0) {
    return "No hay noticias o actividades recientes en el timeline en este momento.";
}

// 5. RETORNAR EL STRING PLANO AL AGENTE (Limitado a las últimas 8 noticias para no saturar)
return "NOVEDADES Y ACTIVIDADES RECIENTES DE LA FACULTAD:\n\n" + noticiasProcesadas.slice(0, 8).join('\n\n---\n\n');

// 1. PETICIÓN AUTÓNOMA AL ENDPOINT DE PLANES
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestionapp.info.unlp.edu.ar/api/PLANES_ESTUDIOS',
  json: true
});

// 2. VALIDAR Y EXTRAER LOS DATOS
// Asumiendo que el endpoint devuelve un array directo o un objeto con una lista
const planes = Array.isArray(response) ? response : (response.planes || []);

// 3. PROCESAR Y FORMATEAR LOS NOMBRES DE CARRERAS/PLANES
const listaPlanes = planes.map(p => {
    const nombre = p.nombre || p.descripcion || "Plan sin nombre";
    const codigo = p.codigo || p.id || "";
    return `- ${nombre} ${codigo ? `(Código: ${codigo})` : ""}`;
}).filter(n => n !== "");

// 4. VALIDACIÓN DE RESULTADOS
if (listaPlanes.length === 0) {
    return "Actualmente no hay información disponible sobre los planes de estudio.";
}

// 5. RETORNAR EL STRING PLANO AL AGENTE
return "PLANES DE ESTUDIO Y CARRERAS DISPONIBLES:\n\n" + listaPlanes.join('\n');
